final:
module gray_code_counter(
	input clk,
	input reset,
	output reg [2:0] gray_code);

reg [2:0] unused_binary_count;

always @(posedge clk) begin
	if (reset)
		unused_binary_count <= 3'b000;
	else
		unused_binary_count <= unused_binary_count + 1;
end

always @(unused_binary_count) begin
	gray_code = unused_binary_count ^ (unused_binary_count >> 1);
end

endmodule
